<script setup>
import { onMounted, ref } from 'vue'; import { getMatches } from '../api'; import PageHeader from '../components/PageHeader.vue'; import { salaryRange } from '../utils/format'
const matches=ref([]); onMounted(async()=>matches.value=await getMatches())
</script>
<template><div><PageHeader eyebrow="AI MATCHING" title="智能匹配报告" subtitle="技能、城市、薪资和经验四维评分，每一分都有依据。"><RouterLink class="btn primary" to="/jobs">生成新报告</RouterLink></PageHeader><div class="match-list" v-if="matches.length"><article v-for="m in matches" :key="m.id" class="match-card"><div class="score-ring" :style="{'--score':m.score}"><span><b>{{m.score}}</b><small>综合分</small></span></div><div class="match-main"><span class="eyebrow">{{m.job.company}} · {{m.job.city}}</span><h2>{{m.job.title}}</h2><p>{{m.summary}}</p><div class="skill-line"><strong>优势技能</strong><span v-for="s in (m.matchedSkills||'待补充').split(',')" :key="s" class="tag good">{{s}}</span></div><div class="skill-line"><strong>提升方向</strong><span v-for="s in (m.missingSkills||'暂无明显短板').split(',')" :key="s" class="tag warn">{{s}}</span></div></div><div class="match-meta"><b>{{salaryRange(m.job)}}</b><small>{{m.job.experienceYears}}年 · {{m.job.education}}</small></div></article></div><div v-else class="empty-state"><span>◎</span><h2>还没有匹配报告</h2><p>从职位雷达选择感兴趣的岗位，AI 将给出可解释评分。</p><RouterLink class="btn primary" to="/jobs">去选择职位</RouterLink></div></div></template>
